## React Data Fetching Component

Here's a complete implementation:

```tsx
import { useState, useEffect } from 'react';

interface DataRow {
  id: number;
  name: string;
}

export function DataTable({ url }: { url: string }) {
  const [data, setData] = useState<DataRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetch(url)
      .then(res => {
        if (!res.ok) throw new Error(res.statusText);
        return res.json();
      })
      .then(setData)
      .catch(err => setError(err.message))
      .finally(() => setLoading(false));
  }, [url]);

  if (loading) return <div>Loading...</div>;
  if (error) return <div>Error: {error}</div>;

  return <table>{data.map(r => <tr key={r.id}><td>{r.name}</td></tr>)}</table>;
}
```

### Key points:
1. Loading state with useState
2. Error handling in fetch
3. Cleanup not needed for single fetch
